use std::collections::{HashMap, VecDeque};

fn is_prime(num: i64) -> bool {
    if num <= 1 {
        return false;
    }
    if num == 2 {
        return true;
    }
    if num % 2 == 0 {
        return false;
    }
    let mut i = 3;
    while i * i <= num {
        if num % i == 0 {
            return false;
        }
        i += 2;
    }
    true
}

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 1 {
        return 0;
    }

    let mut prime_to_indices: HashMap<i64, Vec<usize>> = HashMap::new();
    for (i, &num) in nums.iter().enumerate() {
        if is_prime(num) {
            prime_to_indices.entry(num).or_default().push(i);
        }
    }

    let mut divisible_indices: HashMap<i64, Vec<usize>> = HashMap::new();
    for (i, &num) in nums.iter().enumerate() {
        for (&p, _) in &prime_to_indices {
            if num % p == 0 && num != p {
                divisible_indices.entry(p).or_default().push(i);
            }
        }
    }

    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;
    let mut q = VecDeque::new();
    q.push_back(0);

    while let Some(current) = q.pop_front() {
        // Check adjacent moves
        let mut neighbors = Vec::new();
        if current > 0 {
            neighbors.push(current - 1);
        }
        if current < n - 1 {
            neighbors.push(current + 1);
        }

        for &neighbor in &neighbors {
            if dist[neighbor] > dist[current] + 1 {
                dist[neighbor] = dist[current] + 1;
                q.push_back(neighbor);
